map.centerAndZoom(new BMap.Point(116.404, 39.915), 14); 
var transit &#x3D; new BMap.TransitRoute(map, &#123; 
    renderOptions: &#123; 
        map: map, 
        autoViewport: true 
    &#125; 
&#125;);
